# SAP muestra mensajes en la barra superior (urMsgBar)
# NO es popup, pero es la forma principal de feedback

def read_sap_message(page):
    '''Lee el ultimo mensaje de la barra de SAP.'''
    work = get_work_area(page)
    selectors = [
        '[class*="urMsgBarTxt"]',
        '[class*="urMsgBar"] span',
        '[class*="sapMsgBarMsg"]',
    ]
    for sel in selectors:
        try:
            msg = work.locator(sel)
            if msg.count() > 0:
                text = msg.first.text_content().strip()
                if text:
                    return text
        except:
            continue
    return ""

def check_sap_error(page):
    '''Verifica si hay error en la barra de mensajes.'''
    msg = read_sap_message(page)
    error_indicators = ['error', 'failed', 'invalid', 'not found',
                        'already exists', 'mandatory', 'required']
    is_error = any(ind in msg.lower() for ind in error_indicators)
    return {'message': msg, 'is_error': is_error}

# Uso despues de Save:
work.locator('[title="Save"]').click()
page.wait_for_load_state('networkidle')
result = check_sap_error(page)
if result['is_error']:
    print(f'ERROR SAP: {result["message"]}')
else:
    print(f'OK: {result["message"]}')

