# SAP CRM usa event handlers propios. A veces .fill() no dispara el evento
# que SAP necesita para procesar el valor.

# Disparar eventos manualmente via JS:
sap_frame.evaluate('''(selector, value) => {
    const el = document.querySelector(selector);
    el.value = value;
    // Disparar eventos que SAP escucha:
    el.dispatchEvent(new Event('input', {bubbles: true}));
    el.dispatchEvent(new Event('change', {bubbles: true}));
    el.dispatchEvent(new Event('blur', {bubbles: true}));
    // SAP especifico - sapUI5 events:
    el.dispatchEvent(new Event('liveChange', {bubbles: true}));
}''', '[aria-label*="Account"]', 'IBM')

# Tambien: simular keypress
sap_frame.evaluate('''(selector) => {
    const el = document.querySelector(selector);
    el.dispatchEvent(new KeyboardEvent('keydown', {key: 'Tab', keyCode: 9}));
    el.dispatchEvent(new KeyboardEvent('keyup', {key: 'Tab', keyCode: 9}));
}''', '[aria-label*="Account"]')

# CUANDO USAR ESTO:
# - .fill() pone el valor pero SAP no lo reconoce
