    const results = [];
    // Inputs
    document.querySelectorAll("input:not([type='hidden'])").forEach(el => {
        if (el.offsetParent !== null) {  // solo visibles
            results.push({
                type: 'input',
                label: el.getAttribute('aria-label') || el.getAttribute('title') || el.name || '',
                value: el.value,
                readonly: el.readOnly || el.disabled,
                className: el.className
            });
        }
    });
    // Textareas
    document.querySelectorAll("textarea").forEach(el => {
        if (el.offsetParent !== null) {
            results.push({
                type: 'textarea',
                label: el.getAttribute('aria-label') || '',
                value: el.value
            });
        }
    });
    // Spans con valores (SAP muestra valores read-only como spans)
    document.querySelectorAll("span[class*='urTxtStd']").forEach(el => {
        if (el.offsetParent !== null && el.textContent.trim()) {
            results.push({
                type: 'display',
                value: el.textContent.trim()
            });
        }
