# SAP muestra un spinner/overlay cuando procesa. Hay que esperarlo.

# Metodo 1: Esperar que desaparezca el busy indicator via JS
def wait_sap_not_busy(page, timeout=15):
    '''Espera que SAP termine de procesar.'''
    page.wait_for_function('''() => {
        // Buscar en todos los frames
        function checkFrame(doc) {
            const busy = doc.querySelector('.urBusy, [class*="urLoadingOverlay"], .sapUiLocalBusy');
            if (busy && busy.offsetParent !== null) return false;
            // Revisar iframes
            const iframes = doc.querySelectorAll('iframe');
            for (const iframe of iframes) {
                try {
                    if (!checkFrame(iframe.contentDocument)) return false;
                } catch(e) {}  // cross-origin
            }
            return true;
        }
        return checkFrame(document);
    }''', timeout=timeout * 1000)

# Metodo 2: Verificar pendientes XHR
def wait_no_pending_xhr(page, timeout=15):
    page.wait_for_function('''() => {
        return window.performance.getEntriesByType("resource")
            .filter(r => !r.responseEnd).length === 0;
    }''', timeout=timeout * 1000)

# Uso:
work.locator('[title="Save"]').click()
wait_sap_not_busy(page)
work = get_work_area(page)

