import functools
from datetime import datetime

def screenshot_on_error(func):
    '''Decorador: captura screenshot si la funcion falla.'''
    @functools.wraps(func)
    def wrapper(driver, *args, **kwargs):
        try:
            return func(driver, *args, **kwargs)
        except Exception as e:
            ts = datetime.now().strftime('%Y%m%d_%H%M%S')
            filename = f'sap_error_{func.__name__}_{ts}.png'
            try:
                driver.switch_to.default_content()
                driver.save_screenshot(filename)
                print(f'Screenshot guardado: {filename}')
            except:
                pass
            raise
    return wrapper

@screenshot_on_error
def fill_account(driver, value):
    enter_sap_frames(driver)
    el = driver.find_element(By.CSS_SELECTOR, '[aria-label*="Account"]')
    el.clear()
    el.send_keys(value, Keys.TAB)

# Playwright equivalente:
