def extract_sap_form(page, get_work_area_fn):
    '''Extrae label:value de todos los campos visibles.'''
    work = get_work_area_fn(page)
    fields = {}

    # Inputs con aria-label
    inputs = work.locator('input[aria-label]:not([type="hidden"])')
    for i in range(inputs.count()):
        inp = inputs.nth(i)
        if inp.is_visible():
            label = inp.get_attribute('aria-label') or ''
            value = inp.input_value()
            if label:
                fields[label] = value

    # Inputs con label asociado via xpath
    labels = work.locator('label')
    for i in range(labels.count()):
        lbl = labels.nth(i)
        if lbl.is_visible():
            label_text = lbl.text_content().strip()
            # Buscar input siguiente
            sibling_input = lbl.locator('xpath=./following::input[1]')
            if sibling_input.count() > 0:
                fields[label_text] = sibling_input.first.input_value()

    # Spans de display (campos read-only)
    display_spans = work.locator('[class*="urTxtStd"]')
    for i in range(display_spans.count()):
        span = display_spans.nth(i)
        if span.is_visible():
            text = span.text_content().strip()
            if text and len(text) < 200:
                parent_label = span.locator('xpath=./preceding::label[1]')
                if parent_label.count() > 0:
                    fields[parent_label.first.text_content().strip()] = text

    return fields

