import time
import functools

def sap_retry(max_attempts=3, backoff=2, reraise=True):
    '''Decorador: reintenta operacion SAP con backoff exponencial.'''
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            last_error = None
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_error = e
                    if attempt < max_attempts:
                        wait = backoff ** attempt
                        print(f'Intento {attempt} fallo: {e}. Reintentando en {wait}s...')
                        time.sleep(wait)
                        # Re-obtener frame por si se invalido
                        if args and hasattr(args[0], 'frames'):
                            pass  # page object, re-frame en la funcion
            if reraise:
                raise last_error
            return None
        return wrapper
    return decorator

@sap_retry(max_attempts=3, backoff=2)
def fill_account(page, value):
    work = get_work_area(page)
    field = work.locator('[aria-label*="Account"]')
    field.wait_for(state='visible', timeout=5000)
    field.fill(value)
    field.press('Tab')
    page.wait_for_timeout(500)

