def is_session_valid(page):
    '''Verifica si la sesion SAP sigue activa.'''
    try:
        # Verificar que el frame principal existe
        page.wait_for_selector('frame[name="WorkAreaFrame1"]', timeout=3000)
        return True
    except:
        pass

    # Verificar si hay pagina de login
    try:
        login = page.locator('input[name="sap-user"]')
        if login.count() > 0 and login.first.is_visible():
            return False
    except:
        pass

    # Verificar si hay error de sesion
    try:
        body_text = page.text_content('body') or ''
        if any(x in body_text.lower() for x in ['session expired', 'timed out', 'logon']):
            return False
    except:
        pass

    return True

def ensure_session(page, user, password, client='500'):
    '''Reconecta si la sesion expiro.'''
    if not is_session_valid(page):
        print('Sesion expirada, reconectando...')
        sap_login(page, user, password, client)
        handle_login_popups(page)
        return True  # reconecto
    return False  # sesion valida

# Usar antes de cada operacion importante:
