class SAPError(Exception):
    pass

class SAPSessionExpired(SAPError):
    pass

class SAPFieldValidationError(SAPError):
    pass

class SAPElementNotFound(SAPError):
    pass

def safe_sap_action(page, action_fn, description='', screenshot=True):
    '''Wrapper seguro para acciones SAP.'''
    try:
        result = action_fn(page)
        return {'success': True, 'result': result}
    except TimeoutError as e:
        # Verificar si es sesion expirada
        if not is_session_valid(page):
            raise SAPSessionExpired(f'{description}: sesion expirada')
        if screenshot:
            page.screenshot(path=f'sap_timeout_{description}.png')
        raise SAPElementNotFound(f'{description}: elemento no encontrado - {e}')
    except Exception as e:
        # Leer barra de mensajes SAP
        try:
            msg = read_sap_message(page)
            if msg:
                raise SAPFieldValidationError(f'{description}: SAP dice: {msg}')
        except:
            pass
        if screenshot:
            try:
                page.screenshot(path=f'sap_error_{description}.png')
            except:
                pass
        raise SAPError(f'{description}: {e}')

# Uso:
result = safe_sap_action(page,
    lambda p: fill_account(p, 'IBM'),
    description='fill_account')
